export { default as SBadge } from './badge.vue';

export type * from '@soybeanjs/headless/badge';
export type * from './types';

import type { BadgeCompactProps, BadgeRootEmits, BadgeUi } from '@soybeanjs/headless/badge';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { BadgePosition } from '@/styles/badge';
import type { ThemeColor, ThemeSize } from '@/theme';

/**
 * Properties for the Badge component.
 */
export interface BadgeProps extends BadgeCompactProps {
  /**
   * root class
   */
  class?: ClassValue;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<BadgeUi>;
  /**
   * Position.
   */
  position?: BadgePosition;
}

/**
 * Events for the Badge component.
 */
export type BadgeEmits = BadgeRootEmits;

export type { BadgePosition };

// @unocss-include
import { scv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const badgeVariants = scv({
  slots: {
    root: 'relative inline-block',
    content: `absolute flex justify-center items-center leading-relaxed whitespace-nowrap rounded-full transform`
  },
  variants: {
    color: {
      primary: {
        content: 'bg-primary text-primary-foreground'
      },
      destructive: {
        content: 'bg-destructive text-destructive-foreground'
      },
      success: {
        content: 'bg-success text-success-foreground'
      },
      warning: {
        content: 'bg-warning text-warning-foreground'
      },
      info: {
        content: 'bg-info text-info-foreground'
      },
      carbon: {
        content: 'bg-carbon text-carbon-foreground'
      },
      secondary: {
        content: 'bg-secondary text-secondary-foreground'
      },
      accent: {
        content: 'bg-accent text-accent-foreground'
      }
    },
    size: {
      xs: {
        content: `min-h-2 px-1 text-4xs`
      },
      sm: {
        content: `min-h-2.5 px-1.25 text-3xs`
      },
      md: {
        content: `min-h-3 px-1.5 text-2xs`
      },
      lg: {
        content: `min-h-3.5 px-1.75 text-xs`
      },
      xl: {
        content: `min-h-4 px-2 text-sm`
      },
      '2xl': {
        content: `min-h-5 px-2.5 text-base`
      }
    },
    position: {
      'top-right': {
        content: 'end-0 top-0 translate-x-1/2 -translate-y-1/2 rtl:-translate-x-1/2'
      },
      'bottom-right': {
        content: 'end-0 bottom-0 translate-x-1/2 translate-y-1/2 rtl:-translate-x-1/2'
      },
      'top-left': {
        content: 'start-0 top-0 -translate-x-1/2 -translate-y-1/2 rtl:translate-x-1/2'
      },
      'bottom-left': {
        content: 'start-0 bottom-0 -translate-x-1/2 translate-y-1/2 rtl:translate-x-1/2'
      }
    }
  },
  defaultVariants: {
    color: 'primary',
    size: 'md',
    position: 'top-right'
  }
});

type BadgeVariants = VariantProps<typeof badgeVariants>;

export type BadgePosition = NonNullable<BadgeVariants['position']>;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
